import { useState } from "react";
import { saveVitals } from "../services/api";
import { useNavigate } from "react-router-dom";

function Vitals() {
  const userId = localStorage.getItem("user_id");
  const navigate = useNavigate();

  const [glucose, setGlucose] = useState("");
  const [height, setHeight] = useState("");
  const [weight, setWeight] = useState("");
  const [systolic, setSystolic] = useState("");
  const [diastolic, setDiastolic] = useState("");
  const [heartRate, setHeartRate] = useState("");
  const [spo2, setSpo2] = useState("");
  const [temperature, setTemperature] = useState("");

  const bmi =
    height && weight ? (weight / ((height / 100) ** 2)).toFixed(2) : "";

  const handleSave = async () => {
    try {
      await saveVitals({
        user_id: userId,
        glucose,
        height,
        weight,
        bmi,
        systolic_bp: systolic,
        diastolic_bp: diastolic,
        heart_rate: heartRate,
        spo2,
        temperature
      });
      alert("Vitals saved successfully");
      navigate("/consult");
    } catch (e) {
      alert("Failed to save vitals");
    }
  };

  return (
    <div>
      <h2>Enter Vitals</h2>

      <input placeholder="Glucose" onChange={e => setGlucose(e.target.value)} />
      <input placeholder="Height (cm)" onChange={e => setHeight(e.target.value)} />
      <input placeholder="Weight (kg)" onChange={e => setWeight(e.target.value)} />
      <input placeholder="Systolic BP" onChange={e => setSystolic(e.target.value)} />
      <input placeholder="Diastolic BP" onChange={e => setDiastolic(e.target.value)} />
      <input placeholder="Heart Rate" onChange={e => setHeartRate(e.target.value)} />
      <input placeholder="SpO2" onChange={e => setSpo2(e.target.value)} />
      <input placeholder="Temperature" onChange={e => setTemperature(e.target.value)} />

      <p><b>BMI:</b> {bmi}</p>

      <button onClick={handleSave}>Save Vitals</button>
    </div>
  );
}

export default Vitals;
